    {"id": 16, "texto": "¿Qué es una ceramida?", "opciones": {"a": "Esfingosina + 1 ácido graso", "b": "Glicerol + 3 ácidos grasos", "c": "Colesterol + fosfato", "d": "Glucosa + Fructosa"}, "respuesta_correcta": "a", "explicacion": "Es la molécula base precursora de todos los esfingolípidos."},
