    # --- SECCIÓN 2: PROTEÍNAS ---
    {"id": 31, "texto": "Monómeros de las proteínas:", "opciones": {"a": "Nucleótidos", "b": "Monosacáridos", "c": "Aminoácidos", "d": "Ácidos grasos"}, "respuesta_correcta": "c", "explicacion": "Las proteínas son polímeros de aminoácidos."},
    {"id": 32, "texto": "Enlace que une aminoácidos:", "opciones": {"a": "Peptídico", "b": "Glucosídico", "c": "Éster", "d": "Fosfodiéster"}, "respuesta_correcta": "a", "explicacion": "Es un tipo de enlace amida."},
