    {"id": 41, "texto": "Estructura primaria:", "opciones": {"a": "Plegamiento 3D", "b": "Secuencia lineal de aminoácidos", "c": "Unión de varias cadenas", "d": "Hélice alfa"}, "respuesta_correcta": "b", "explicacion": "Es el orden exacto dictado por el genoma."},
    {"id": 42, "texto": "Hélice alfa y Lámina beta son ejemplos de estructura:", "opciones": {"a": "Primaria", "b": "Secundaria", "c": "Terciaria", "d": "Cuaternaria"}, "respuesta_correcta": "b", "explicacion": "Son patrones de plegamiento locales."},
