    {"id": 44, "texto": "Nivel donde la proteína es funcional y tridimensional:", "opciones": {"a": "Primario", "b": "Secundario", "c": "Terciario", "d": "Cuaternario"}, "respuesta_correcta": "c", "explicacion": "La estructura terciaria le da su conformación activa final."},
